import React from "react";

// Zero-dependency modern ana sayfa: sadece React ve saf CSS kullanır.
// Tailwind, shadcn veya ikon kütüphanesi gerekmez.
// Bu dosyayı src/AnaSayfa.js olarak kaydedip doğrudan kullanabilirsiniz.

export default function AnaSayfa() {
    return (
        <div className="app-root">
            <style>{`
        :root{
          --bg: #0b0b10; /* koyu arka plan */
          --text: #e7e7ed;
          --muted: #a0a0ad;
          --card: #12121a;
          --card-2: #14141f;
          --border: #242434;
          --brand-1: #6c7cff; /* indigo */
          --brand-2: #a855f7; /* fuchsia-ish */
          --brand-3: #22c55e; /* emerald */
        }
        .app-root{
          min-height:100dvh; color:var(--text);
          background: radial-gradient(80rem 40rem at 20% -10%, rgba(108,124,255,.25), transparent 60%),
                      radial-gradient(60rem 30rem at 120% 10%, rgba(168,85,247,.18), transparent 60%),
                      radial-gradient(70rem 30rem at 50% 120%, rgba(34,197,94,.18), transparent 60%),
                      linear-gradient(180deg, #0b0b10 0%, #0e0e14 60%, #0b0b10 100%);
        }
        .container{ max-width:1120px; margin:0 auto; padding:24px; }
        .nav{ position:sticky; top:0; backdrop-filter:saturate(1.2) blur(8px);
              background:rgba(15,15,22,.4); border-bottom:1px solid var(--border); z-index:10; }
        .nav-inner{ display:flex; align-items:center; justify-content:space-between; padding:12px 24px; }
        .brand{ display:flex; align-items:center; gap:10px; font-weight:700; letter-spacing:.2px; }
        .badge{ display:inline-flex; align-items:center; gap:8px; border:1px solid #2a2a3a; background:#141422; color:#c9c9d6;
                padding:6px 10px; border-radius:999px; font-size:12px; opacity:.95; }
        .dot{ width:8px; height:8px; border-radius:50%; background:var(--brand-3); box-shadow:0 0 12px rgba(34,197,94,.9); }
        .hero{ display:grid; gap:28px; grid-template-columns:1fr; padding:56px 24px 16px; }
        @media(min-width:960px){ .hero{ grid-template-columns:1.1fr .9fr; align-items:center; gap:44px; padding-top:72px; } }
        .title{ font-size:40px; line-height:1.08; font-weight:900; letter-spacing:-.02em; }
        @media(min-width:640px){ .title{ font-size:56px; } }
        .gradient{ background:linear-gradient(90deg,var(--brand-1),var(--brand-2),var(--brand-3));
                   -webkit-background-clip:text; background-clip:text; color:transparent; }
        .lead{ color:var(--muted); max-width:640px; margin-top:12px; }
        .cta-row{ display:flex; flex-wrap:wrap; gap:12px; margin-top:16px; }
        .btn{ appearance:none; border:none; padding:12px 16px; border-radius:16px; font-weight:600; cursor:pointer;
              background:var(--brand-1); color:white; box-shadow:0 8px 20px rgba(108,124,255,.25); transition:.2s transform,.2s background; }
        .btn:hover{ transform:translateY(-1px); background:#5c6cff; }
        .btn-outline{ background:transparent; color:#d6d6e3; border:1px solid #2a2a3a; }
        .btn-outline:hover{ background:#151522; }
        .meta{ display:grid; grid-template-columns:repeat(3,1fr); gap:10px; max-width:440px; margin-top:16px; }
        .pill{ border:1px solid #2a2a3a; background:#121220; padding:10px 12px; border-radius:14px; }
        .pill span{ display:block; font-size:12px; color:#9a9ab0; }
        .pill strong{ font-size:14px; }
        .device{ border:1px solid var(--border); background:linear-gradient(180deg,#10101a 0%,#0f0f18 100%);
                 padding:16px; border-radius:26px; box-shadow:0 16px 48px rgba(0,0,0,.35); }
        .device-inner{ height:320px; border:1px dashed #2b2b3b; border-radius:18px; display:grid; place-items:center;
                        background:radial-gradient(60rem 24rem at 50% 10%, rgba(108,124,255,.08), transparent 50%),
                                   radial-gradient(40rem 18rem at 40% 60%, rgba(168,85,247,.08), transparent 50%),
                                   radial-gradient(30rem 14rem at 70% 70%, rgba(34,197,94,.08), transparent 50%); }
        .grid{ display:grid; gap:16px; grid-template-columns:1fr; }
        @media(min-width:720px){ .grid{ grid-template-columns:repeat(3,1fr); } }
        .card{ border:1px solid var(--border); background:var(--card); border-radius:18px; padding:18px; }
        .card h3{ display:flex; align-items:center; gap:10px; font-size:16px; margin:0 0 8px; }
        .card p{ margin:0; color:var(--muted); font-size:14px; }
        .icon{ width:18px; height:18px; }
        .section{ padding:24px; margin-top:36px; border:1px solid var(--border); border-radius:24px; background:var(--card-2); text-align:center; }
        footer{ color:#8a8aa0; font-size:13px; padding:36px 24px; }
        .links{ display:flex; gap:16px; }
        .links a{ color:#a9a9bf; text-decoration:none; }
        .links a:hover{ color:#d0d0ea; }
      `}</style>

            <header className="nav">
                <div className="nav-inner container">
                    <div className="brand">
                        {Logo()}
                        <span>Markanız</span>
                    </div>
                    <div className="links" aria-label="Primary">
                        <a href="#features">Özellikler</a>
                        <a href="#pricing">Fiyatlar</a>
                        <a href="#about">Hakkımızda</a>
                    </div>
                </div>
            </header>

            <main className="container">
                <section className="hero">
                    <div>
                        <div className="badge"><span className="dot" /> En güncel, hızlı ve şık deneyim</div>
                        <h1 className="title" style={{ marginTop: 12 }}>
                            Hoş Geldiniz! <br />
                            <span className="gradient">Modern Ana Sayfa</span>
                        </h1>
                        <p className="lead">Burası ana sayfanızın modern yorumudur. Ek bağımlılık olmadan şık görünüm,
                            hızlı performans ve mobil uyum.</p>
                        <div className="cta-row">
                            <button className="btn">Hemen Başla {ArrowRight()}</button>
                            <button className="btn btn-outline">Daha Fazla Bilgi</button>
                        </div>
                        <div className="meta">
                            <div className="pill"><span>Performans</span><strong>Hızlı</strong></div>
                            <div className="pill"><span>UI</span><strong>Şık</strong></div>
                            <div className="pill"><span>Destek</span><strong>Güncel</strong></div>
                        </div>
                    </div>

                    <div className="device">
                        <div className="device-inner">
                            <p style={{ color: "#b9b9c9", textAlign: "center", maxWidth: 420 }}>
                                Buraya bir ekran görüntüsü, ürün görseli veya canlı demo yerleştirebilirsiniz.
                            </p>
                        </div>
                    </div>
                </section>

                <section id="features" style={{ marginTop: 28 }}>
                    <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 12 }}>
                        <h2 style={{ fontSize: 24, fontWeight: 800 }}>Öne Çıkan Özellikler</h2>
                        <a className="links" href="#">Tümünü Gör</a>
                    </div>
                    <div className="grid">
                        <div className="card">
                            <h3>{ShieldCheck()} Güvenli ve Erişilebilir</h3>
                            <p>Kontrast, odak ve klavye navigasyonu gözetilmiştir.</p>
                        </div>
                        <div className="card">
                            <h3>{Zap()} Hızlı Performans</h3>
                            <p>Minimal render ve optimize görsellerle yüksek skorlar.</p>
                        </div>
                        <div className="card">
                            <h3>{Star()} Şık Tasarım</h3>
                            <p>Zarif tipografi ve yumuşak gölgelerle modern görünüm.</p>
                        </div>
                    </div>
                </section>

                <section className="section" aria-labelledby="cta">
                    <h3 id="cta" style={{ fontSize: 22, fontWeight: 800 }}>Hazır mısınız?</h3>
                    <p style={{ color: "#a8a8bd", maxWidth: 720, margin: "8px auto 0" }}>
                        Projenizi bir üst seviyeye taşıyın. Modern mimari ve şık arayüzlerle fark yaratın.
                    </p>
                    <div className="cta-row" style={{ justifyContent: "center" }}>
                        <button className="btn">Ücretsiz Dene</button>
                        <button className="btn btn-outline">Demo Talep Et</button>
                    </div>
                </section>
            </main>

            <footer className="container">
                <div style={{ display: "flex", gap: 16, alignItems: "center", justifyContent: "space-between", flexWrap: "wrap" }}>
                    <p>© {new Date().getFullYear()} Markanız. Tüm hakları saklıdır.</p>
                    <div className="links">
                        <a href="#">Gizlilik</a>
                        <a href="#">Şartlar</a>
                        <a href="#">İletişim</a>
                    </div>
                </div>
            </footer>
        </div>
    );
}

// Basit SVG ikonları (harici paket yok)
function ArrowRight() {
    return (
        <svg className="icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{ marginLeft: 6 }}>
            <path d="M5 12h14" /><path d="M12 5l7 7-7 7" />
        </svg>
    );
}
function ShieldCheck() {
    return (
        <svg className="icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z" />
            <path d="M9 12l2 2 4-4" />
        </svg>
    );
}
function Zap() {
    return (
        <svg className="icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <polygon points="13 2 3 14 12 14 11 22 21 10 12 10 13 2" />
        </svg>
    );
}
function Star() {
    return (
        <svg className="icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <polygon points="12 2 15 8.5 22 9 17 13.5 18.5 21 12 17.5 5.5 21 7 13.5 2 9 9 8.5 12 2" />
        </svg>
    );
}
function Logo() {
    return (
        <svg width="22" height="22" viewBox="0 0 48 48" fill="none" xmlns="http://www.w3.org/2000/svg">
            <defs>
                <linearGradient id="g" x1="0" y1="0" x2="1" y2="1">
                    <stop offset="0%" stopColor="var(--brand-1)" />
                    <stop offset="50%" stopColor="var(--brand-2)" />
                    <stop offset="100%" stopColor="var(--brand-3)" />
                </linearGradient>
            </defs>
            <rect x="2" y="2" width="44" height="44" rx="12" stroke="url(#g)" strokeWidth="2.5" fill="none" />
            <path d="M14 30c6-1 10-5 12-12 4 6 8 8 14 8-2 6-7 10-14 12-6-1-10-3-12-8z" fill="url(#g)" opacity="0.85" />
        </svg>
    );
}
